class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def promote(self):
        self.king = True

    def is_king(self):
        return self.king

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ["white", "black"]
        for i in range(3):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.set_piece((i, j), Piece(colors[i % 2]))

        for i in range(5, 8):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.set_piece((i, j), Piece(colors[1 - (i % 2)]))

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def set_piece(self, position, piece):
        self.board[position[0]][position[1]] = piece

    def clear_position(self, position):
        self.board[position[0]][position[1]] = None

class CheckersGame:
