        self.board = Board()
        self.current_player = "white"

    def print_board(self):
        for row in self.board.board:
            print(" ".join(["WP" if piece and piece.color == "white" else "BP" if piece and piece.color == "black" else "--" for piece in row]))

    def make_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos)
        if not piece or piece.color != self.current_player:
            return False

        if not self.is_valid_move(from_pos, to_pos):
            return False

        start_x, start_y = from_pos
        end_x, end_y = to_pos
        dx, dy = (end_x - start_x), (end_y - start_y)

        self.board.set_piece(to_pos, piece)
        if abs(dx) == 2:
            mid_x, mid_y = start_x + dx // 2, start_y + dy // 2
            captured_piece = self.board.get_piece((mid_x, mid_y))
            if captured_piece and captured_piece.color != piece.color:
                self.board.clear_position((mid_x, mid_y))
        else:
            if piece.is_king():
                # Handle king promotion logic here
                pass

        self.board.clear_position(from_pos)

        self.current_player = "black" if self.current_player == "white" else "white"
        return True

    def is_valid_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos)
        start_x, start_y = from_pos
        end_x, end_y = to_pos
        dx, dy = (end_x - start_x), (end_y - start_y)

        if not piece:
            return False

        if piece.color != self.current_player:
            return False

        if abs(dx) != 1 or abs(dy) not in [1, 2]:
            return False

        if self.board.get_piece(to_pos):
            return False

        # Add capturing logic here
        if abs(dy) == 2:
            mid_x, mid_y = start_x + dx // 2, start_y + dy // 2
            if not self.board.get_piece((mid_x, mid_y)):
                return False

        return True

    def check_winner(self):
        # Check for winner logic here
        pass

    def play(self):
        while True:
            self.print_board()
            from_pos = input(f"Player {self.current_player}, enter your move (from-to): ").split("-")
            to_pos = tuple(int(pos) for pos in from_pos)
            if not self.make_move(from_pos, to_pos):
                print("Invalid move. Try again.")
            else:
                winner = self.check_winner()
